#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        unsigned int xr = 0, x;
        for(int i=0;i<N;i++){
            scanf("%u", &x);
            xr ^= x;
        }
        if(N%2==1 || xr==0) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

