    it = iter(data)
    t = int(next(it))
    out = []
    for _ in range(t):
        n = int(next(it))
        xr = 0
        for _ in range(n):
            xr ^= int(next(it))
        if n % 2 == 1 or xr == 0:
            out.append('YES')
        else:
            out.append('NO')
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
